def propagate_bounded(atms, justification, depth_cap, max_envs_per_label):
    # justification: (antecedents: List[Node], consequent: Node)
    # Step 1: Cross-product of antecedent labels
    env_set = {frozenset()}
    for ant in justification.antecedents:
        env_set = {a | b for a in env_set for b in ant.label}

    # Step 2: Prune supersets within new env_set
    env_set = minimal_subsets(env_set)

    # Step 3: Filter no-goods
    env_set = {e for e in env_set
               if not any(ng <= e for ng in atms.nogoods)}

    # Step 4: Depth cap (key bounded addition)
    env_set = {e for e in env_set if len(e) <= depth_cap}

    # Step 5: Merge into node label (UPDATE)
    new_label = merge_minimal(justification.consequent.label, env_set)

    # Step 6: Optional size cap
    if len(new_label) > max_envs_per_label:
        new_label = set(sorted(new_label, key=len)[:max_envs_per_label])

    if new_label != justification.consequent.label:
        justification.consequent.label = new_label
        # Propagate to dependent justifications
        for dep_just in atms.justifications_with_antecedent(justification.consequent):
            propagate_bounded(atms, dep_just, depth_cap, max_envs_per_label)

def merge_minimal(existing_label, new_envs):
    merged = set(existing_label)
    for e in new_envs:
        if not any(x <= e for x in merged):  # e not subsumed
            merged = {x for x in merged if not e <= x}  # remove supersets
            merged.add(e)
    return merged

def minimal_subsets(env_set):
    result = set()
    for e in sorted(env_set, key=len):
        if not any(x <= e for x in result):
            result.add(e)
    return result

