from problog.program import PrologString
from problog import get_evaluatable

# Build model from dict of {fact_string: probability}
def run_problog_query(prob_facts: dict, rules: list[str], query: str) -> dict:
    lines = []
    for fact, prob in prob_facts.items():
        lines.append(f'{prob}::{fact}.')
    lines.extend(rules)
    lines.append(f'query({query}).')
    model_str = '\n'.join(lines)
    result = get_evaluatable().create_from(PrologString(model_str)).evaluate()
    return {str(k): float(v) for k, v in result.items()}

# Example:
# prob_facts = {'parent(tom, bob)': 0.8, 'parent(bob, ann)': 0.9}
# rules = ['ancestor(X,Y) :- parent(X,Y).', 'ancestor(X,Y) :- parent(X,Z), ancestor(Z,Y).']
# result = run_problog_query(prob_facts, rules, 'ancestor(tom,ann)')
# => {'ancestor(tom,ann)': 0.72}
